import{_ as t,a,b as o,c as n}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as l,o as i,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Thêm Google Drive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/google-drive.md","filePath":"vi-VN/upload/google-drive.md","lastUpdated":1781962217000}'),r={name:"vi-VN/upload/google-drive.md"};function d(p,e,h,g,u,b){return i(),s("div",null,[...e[0]||(e[0]=[c('<h1 id="them-google-drive-channel" tabindex="-1">Thêm Google Drive Channel <a class="header-anchor" href="#them-google-drive-channel" aria-label="Permalink to &quot;Thêm Google Drive Channel&quot;">​</a></h1><h2 id="can-chuan-bi-truoc" tabindex="-1">Cần chuẩn bị trước <a class="header-anchor" href="#can-chuan-bi-truoc" aria-label="Permalink to &quot;Cần chuẩn bị trước&quot;">​</a></h2><p>Trước khi bắt đầu, chuẩn bị các mục sau:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Vì sao cần</th></tr></thead><tbody><tr><td>Google account</td><td>Dùng để access Google Cloud và authorize Google Drive</td></tr><tr><td>Google Cloud project</td><td>Dùng để enable Drive API và tạo OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed dùng để lấy <code>Client ID</code>, <code>Client Secret</code> và <code>Refresh Token</code></td></tr><tr><td>ImgBed domain của bạn</td><td>Dùng cho OAuth redirect URI. Phải khớp với domain bạn thực sự dùng.</td></tr></tbody></table><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><h3 id="step-1-enable-google-drive-api" tabindex="-1">Step 1: Enable Google Drive API <a class="header-anchor" href="#step-1-enable-google-drive-api" aria-label="Permalink to &quot;Step 1: Enable Google Drive API&quot;">​</a></h3><ol><li>Mở Google Cloud Console.</li><li>Tạo project mới hoặc chọn project có sẵn.</li><li>Vào <code>APIs &amp; Services</code>.</li><li>Nhấn <code>Enable APIs and Services</code>.</li><li>Tìm <code>Google Drive API</code>.</li><li>Mở và nhấn enable.</li></ol><h3 id="step-2-configure-oauth-consent-screen" tabindex="-1">Step 2: Configure OAuth Consent Screen <a class="header-anchor" href="#step-2-configure-oauth-consent-screen" aria-label="Permalink to &quot;Step 2: Configure OAuth Consent Screen&quot;">​</a></h3><ol><li>Trong Google Cloud, mở <code>Google Auth Platform</code>.</li><li>Hoàn tất thông tin <code>Branding</code> cơ bản, như app name, support email và developer contact email.</li><li>Mở <code>Audience</code>.</li><li>Với hầu hết self-hosted personal deployments, chọn <code>External</code>.</li><li>Nếu chọn <code>External</code>, thêm Google account bạn muốn authorize vào <code>Test users</code>.</li><li>Mở <code>Data Access</code>.</li><li>Thêm Google Drive permissions cần thiết.</li></ol><h3 id="step-3-tao-oauth-2-0-client" tabindex="-1">Step 3: Tạo OAuth 2.0 Client <a class="header-anchor" href="#step-3-tao-oauth-2-0-client" aria-label="Permalink to &quot;Step 3: Tạo OAuth 2.0 Client&quot;">​</a></h3><ol><li>Trong <code>Google Auth Platform</code>, mở <code>Clients</code>.</li><li>Tạo client mới.</li><li>Đặt application type là <code>Web application</code>.</li><li>Đặt tên client dễ nhận biết.</li><li>Với authorized JavaScript origins, nhập ImgBed URL, ví dụ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Với authorized redirect URIs, nhập:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>Sau khi client được tạo, copy các giá trị này:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-đien-google-drive-channel" tabindex="-1">Step 4: Điền Google Drive Channel <a class="header-anchor" href="#step-4-đien-google-drive-channel" aria-label="Permalink to &quot;Step 4: Điền Google Drive Channel&quot;">​</a></h2><p>Trong Upload Settings, chọn <code>Google Drive</code> và điền:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Nhập gì</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết, ví dụ <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID từ Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret từ Google Cloud</td></tr><tr><td>Refresh Token</td><td>Tạm thời để trống. Lấy ở bước tiếp theo.</td></tr><tr><td>Root directory</td><td>Optional. Mặc định là <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-lay-refresh-token" tabindex="-1">Step 5: Lấy Refresh Token <a class="header-anchor" href="#step-5-lay-refresh-token" aria-label="Permalink to &quot;Step 5: Lấy Refresh Token&quot;">​</a></h2><ol><li>Nhấn <code>Get Token</code>.</li><li>Chọn Google account bạn muốn kết nối.</li><li>Hoàn tất authorization prompts.</li><li>Callback page sẽ hiển thị <code>Refresh Token</code>.</li><li>Copy token đó.</li><li>Quay lại ImgBed và paste vào field <code>Refresh Token</code>.</li></ol><p><img src="'+n+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>Nếu sau này đổi Google account, đổi OAuth client hoặc authorization cũ hết hạn, bạn không cần xóa channel. Mở edit page và nhấn <code>Reauthorize</code>.</p><h2 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h2><p>Sau khi điền đủ fields, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mở Google Cloud</span></span>
<span class="line"><span>-&gt; Tạo hoặc chọn project</span></span>
<span class="line"><span>-&gt; Enable Google Drive API</span></span>
<span class="line"><span>-&gt; Configure Google Auth Platform</span></span>
<span class="line"><span>-&gt; Nếu Audience là External, thêm Google account của bạn vào Test users</span></span>
<span class="line"><span>-&gt; Tạo Web application OAuth client</span></span>
<span class="line"><span>-&gt; Dùng https://your-domain.com/api/oauth/google/callback làm redirect URI</span></span>
<span class="line"><span>-&gt; Điền Client ID và Client Secret vào ImgBed</span></span>
<span class="line"><span>-&gt; Nhấn Get Token</span></span>
<span class="line"><span>-&gt; Sign in bằng Google và authorize</span></span>
<span class="line"><span>-&gt; Copy Refresh Token từ callback page</span></span>
<span class="line"><span>-&gt; Paste lại vào ImgBed và save</span></span>
<span class="line"><span>-&gt; Upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const k=l(r,[["render",d]]);export{f as __pageData,k as default};
